public class Main {
    public static void main(String[] args) {
        try {
            int[] scores = {90, 80, 70};
            System.out.println("First score: " + scores[0]);
            System.out.println("Now reaching for score number 5...");
            System.out.println(scores[5]);
            System.out.println("This line never runs.");
        } catch (ArrayIndexOutOfBoundsException e) {
            System.out.println("Oops! That spot in the array does not exist.");
        }
        System.out.println("The program keeps going. No crash!");
    }
}

public class Main {
    public static void main(String[] args) {
        int[] tries = {10, 0, 5};

        for (int divisor : tries) {
            try {
                int answer = 100 / divisor;
                System.out.println("100 / " + divisor + " = " + answer);
            } catch (ArithmeticException e) {
                System.out.println("Cannot divide " + 100 + " by " + divisor + " — skipping!");
            }
        }

        try {
            String notANumber = "banana";
            int n = Integer.parseInt(notANumber);
            System.out.println(n);
        } catch (NumberFormatException e) {
            System.out.println("'banana' is not a number, so I will use 0 instead.");
        }

        System.out.println("All done, safe and sound.");
    }
}

public class Main {
    public static void main(String[] args) {
        String[] words = {"7", "oops", null};

        for (String word : words) {
            System.out.println("Trying word: " + word);
            try {
                int length = word.length();
                int number = Integer.parseInt(word);
                System.out.println("  Length " + length + ", number is " + number);
            } catch (NullPointerException e) {
                System.out.println("  That word was missing (null)!");
            } catch (NumberFormatException e) {
                System.out.println("  That word is not a number!");
            } finally {
                System.out.println("  Finished checking this word.");
            }
        }

        System.out.println("Every word handled. Nothing crashed.");
    }
}

public class Main {
    static void checkAge(int age) throws TooYoungException {
        if (age < 13) {
            throw new TooYoungException("Age " + age + " is too young — must be 13 or older.");
        }
        System.out.println("Age " + age + " is allowed in. Welcome!");
    }

    public static void main(String[] args) {
        int[] ages = {15, 9};
        for (int age : ages) {
            try {
                checkAge(age);
            } catch (TooYoungException e) {
                System.out.println("Sorry: " + e.getMessage());
            }
        }
        System.out.println("Door check complete.");
    }
}

class TooYoungException extends Exception {
    TooYoungException(String message) {
        super(message);
    }
}

