public class Main {
    static void buyTicket(int money) throws NotEnoughMoneyException {
        if (money < 10) {
            throw new NotEnoughMoneyException("Need 10 coins, but only have " + money + ".");
        }
        System.out.println("Ticket bought with " + money + " coins!");
    }

    public static void main(String[] args) {
        int[] wallets = {15, 4};
        for (int money : wallets) {
            try {
                buyTicket(money);
            } catch (NotEnoughMoneyException e) {
                System.out.println("No ticket: " + e.getMessage());
            }
        }
        System.out.println("Ticket booth closed.");
    }
}

class NotEnoughMoneyException extends Exception {
    NotEnoughMoneyException(String message) {
        super(message);
    }
}
